# detect invalid: unit price != catalog unit price (tolerance), or discount outside 0-100, or quantity not positive integer
m['unit_price_mismatch'] = (m['CatalogUnitPrice'].notna()) & ((m['UnitPrice']-m['CatalogUnitPrice']).abs()>1e-6)
m['discount_invalid'] = (m['Discount'].isna()) | (m['Discount']<0) | (m['Discount']>100)
